import { ElementRef, Injectable } from "@angular/core";
import { FormControl, FormGroup } from "@angular/forms";

@Injectable({
  providedIn: "root",
})
export class ScrollingService {
  constructor() {}

  public async findInvalidControls(formGroup: FormGroup): Promise<void> {
    const invalidControlNames = Object.keys(formGroup.controls).filter(
      (name) => formGroup.controls[name].invalid
    );
    if (invalidControlNames.length > 0) {
      const formControl = document.querySelector(
        `[formcontrolname="${invalidControlNames[0]}"]`
      ) as HTMLElement;

      formControl.scrollIntoView({
        block: "center",
        behavior: "smooth",
      });
    }
  }

  public scrollToTop() {
    const scrollHandler = async (event) => {
      await event.target.scrollTo({
        top: 0,
        behavior: "smooth",
      });
      window.removeEventListener("scroll", scrollHandler, true);
    };
    window.addEventListener("scroll", scrollHandler, true);
  }

  scrollToPoint(elementId) {
    const el = document.getElementById(`${elementId}`);
    if (el != null) {
      el.scrollIntoView({
        behavior: "smooth",
        block: "end",
        inline: "nearest",
      });
    }
  }
}
