import { HttpClient } from "@angular/common/http";
import { Injectable } from "@angular/core";
import {
  AgreementInfo,
  AgreementsBalancesBackwardRep,
  AgreementTransInfo,
  GetAgreementsBalancesRequest,
} from "src/app/views/Models/Loan/AgreementInfo";
import { EnvService } from "../env.service";
import { UpdateAgreementRequest } from "src/app/views/Models/Overdraft/Agreement/UpdateAgreement";

@Injectable({
  providedIn: "root",
})
export class AgreementService {
  constructor(private http: HttpClient, private env: EnvService) {}

  getAgreementsByClientKey(clientKey: string, activeAgreement: number) {
    return this.http.get<AgreementInfo[]>(
      `${this.env.API_URL}api/Agreement/GetClientAgreements`,
      {
        params: {
          client_key: clientKey,
          activeAgreement: activeAgreement,
        },
      }
    );
  }
  updateAgreement(request: UpdateAgreementRequest) {
    return this.http.post(`${this.env.API_URL}api/Agreement/UpdateAgreement`, {
      agreementKey: request.agreementKey,
      agreementStatus: request.agreementStatus,
      agreementUuc: request.agreementUuc,
    });
  }
  getAgreementInfo(agreement_key: string) {
    return this.http.get<AgreementInfo[]>(
      `${this.env.API_URL}api/Agreement/GetClientAgreementInfo?agreement_key=${agreement_key}`,
      {}
    );
  }

  getAgreementTransPaging(
    agreement_key: string,
    page: number,
    pagesize: number,
    trans_type: number
  ) {
    return this.http.get<AgreementTransInfo>(
      `${this.env.API_URL}api/Agreement/GetClientAgreementTransPaging?agreement_key=${agreement_key}&page=${page}&pagesize=${pagesize}&trans_type=${trans_type}`,
      {}
    );
  }

  GetAgreementsBalancesBackwardRep(request: GetAgreementsBalancesRequest) {
    return this.http.post<AgreementsBalancesBackwardRep[]>(
      `${this.env.API_URL}api/Agreement/GetAgreementsBalancesBackwardRep`,
      {
        start_date: request.start_date,
        end_date: request.end_date,
        calc_date: request.calc_date,
        all_branches: request.all_branches,
        branch_codes_list: request.branch_codes_list,
        all_loan_types: request.all_loan_types,
        loan_types_list: request.loan_types_list,
        all_officers: request.all_officers,
        officer_keys_list: request.officer_keys_list,
      }
    );
  }
}
