import { HttpClient } from "@angular/common/http";
import { Injectable } from "@angular/core";
import { EnvService } from "./env.service";
import { RescheduleBanks } from "src/app/views/Models/Banks/RescheduleBanks";
import { BranchBanks } from "src/app/views/Models/Banks/BranchBanks";

@Injectable({
  providedIn: "root",
})
export class BankService {
  constructor(private env: EnvService, private http: HttpClient) {}

  getRescheduleBanks = async (): Promise<RescheduleBanks[]> => {
    try {
      const response = await this.http
        .get<RescheduleBanks[]>(
          `${this.env.API_URL}api/Bank/GetRescheduleBanks`
        )
        .toPromise();
      return response;
    } catch (error) {
      console.error("Error fetching GetRescheduleBanks:", error);
      throw error;
    }
  };

  getBranchBanks = async (branch_code: number): Promise<BranchBanks[]> => {
    try {
      const response = await this.http
        .get<BranchBanks[]>(
          `${this.env.API_URL}api/Bank/GetBranchBanks?branch_code=${branch_code}`
        )
        .toPromise();
      return response;
    } catch (error) {
      console.error("Error fetching GetBranchBanks:", error);
      throw error;
    }
  };
}
