import { HttpClient } from "@angular/common/http";
import { Injectable } from "@angular/core";
import { EnvService } from "./env.service";
import { GetInstallmentInformationByInstallmentKey } from "src/app/views/Models/Installments/getInstallmentInformationByInstallmentKey";
import { Observable } from "rxjs";
import { GetInstallmentsByLoanKey } from "src/app/views/Models/Installments/GetInstallmentsByLoanKey";
import { InstallmentsInfo } from "src/app/views/Models/Installments/InstallmentsInfo";

@Injectable({
  providedIn: "root",
})
export class InstallmentsService {
  constructor(private env: EnvService, private http: HttpClient) {}

  getInstallmentInformationByInstallmentKey = (
    installmentKey: string
  ): Observable<GetInstallmentInformationByInstallmentKey> => {
    try {
      return this.http.get<GetInstallmentInformationByInstallmentKey>(
        this.env.API_URL +
          `api/Installments/GetInstallmentInformationByInstallmentKey?installmentKey=${installmentKey}`
      );
    } catch (error) {
      console.error(
        "Error fetching getInstallmentInformationByInstallmentKey:",
        error
      );
      throw error;
    }
  };
  GetInstallmentsInfoByLoanKey = (
    loanKey: string
  ): Observable<InstallmentsInfo[]> => {
    try {
      return this.http.get<InstallmentsInfo[]>(
        this.env.API_URL +
          `api/Installments/GetInstallmentsInfoByLoanKey?loanKey=${loanKey}`
      );
    } catch (error) {
      console.error("Error fetching GetInstallmentsInfoByLoanKey:", error);
      throw error;
    }
  };
  getInstallmentsByLoanKey = (
    loanKey: number
  ): Observable<GetInstallmentsByLoanKey[]> => {
    try {
      return this.http.get<GetInstallmentsByLoanKey[]>(
        this.env.API_URL +
          `api/Installments/GetInstallmentsByLoanKey?loanKey=${loanKey}`
      );
    } catch (error) {
      console.error("Error fetching GetInstallmentsByLoanKey:", error);
      throw error;
    }
  };
}
