import { Injectable } from "@angular/core";
import { EnvService } from "./env.service";
import { HttpClient } from "@angular/common/http";
import { AlertService } from "./alert.service";
import {
  BranchReference,
  UserBranch,
} from "src/app/views/Models/Settings/BranchReference";

@Injectable({
  providedIn: "root",
})
export class BranchService {
  constructor(
    private env: EnvService,
    private http: HttpClient,
    private alertService: AlertService
  ) {}

  getBranches = async () => {
    try {
      return this.http
        .get<BranchReference[]>(this.env.API_URL + `api/Branch/GetBranches`)
        .toPromise();
    } catch (error) {
      console.error("Error Fetching All Branches: ", error);
      throw error;
    }
  };

  addAllBranchesToUser = async (branches: UserBranch[]) => {
    try {
      return this.http
        .post(this.env.API_URL + `api/Branch/AddAllBranchesToUser`, branches)
        .toPromise();
    } catch (error) {
      console.error("Error Adding All Branches To User: ", error);
      throw error;
    }
  };

  addBranchToUser = async (
    user_name: string,
    branch_code: string,
    officer_key: string
  ) => {
    try {
      return this.http
        .post(this.env.API_URL + `api/Branch/AddBranchToUser`, {
          user_name: user_name,
          branch_code: branch_code,
          officer_key: officer_key,
        })
        .toPromise();
    } catch (error) {
      console.error("Error Adding Branch To User: ", error);
      throw error;
    }
  };

  removeBranchFromUser = async (user_name: string, branch_code: string) => {
    try {
      return this.http
        .post(this.env.API_URL + `api/Branch/RemoveBranchFromUser`, {
          user_name: user_name,
          branch_code: branch_code,
        })
        .toPromise();
    } catch (error) {
      console.error("Error Removing Branch From User: ", error);
      throw error;
    }
  };

  removeAllBranchesFromUser = async (user_name: string) => {
    try {
      return this.http
        .post(this.env.API_URL + `api/Branch/RemoveAllBranchesFromUser`, {
          user_name: user_name,
        })
        .toPromise();
    } catch (error) {
      console.error("Error Removing All Branches From User: ", error);
      throw error;
    }
  };

  getAllBranchesWithUserAccess = async (
    user_name: string
  ): Promise<UserBranch[]> => {
    try {
      return this.http
        .get<UserBranch[]>(
          this.env.API_URL +
            `api/Branch/getAllBranchesWithUserAccess?user_name=${user_name}`
        )
        .toPromise();
    } catch (error) {
      console.error("Error Removing All Branches From User: ", error);
      throw error;
    }
  };
}
