import { Injectable } from "@angular/core";

@Injectable({
  providedIn: "root",
})
export class sortingService {
  sortOrder: string = "asc";
  sortNumber: number;

  public sortByParameter(data: any[], parameter: string) {
    if (this.sortOrder == "asc") {
      this.sortNumber = -1;
      this.sortOrder = "desc";
    } else {
      this.sortNumber = 1;
      this.sortOrder = "asc";
    }
    const words: string[] = parameter.split(".");
    data = data.sort((a, b) => {
      let valueA = a[parameter];
      let valueB = b[parameter];

      if (words.length > 0) {
        let currentObjA = a;
        let currentObjB = b;

        for (const word of words) {
          if (currentObjA[word]) {
            currentObjA = currentObjA[word];
            currentObjB = currentObjB[word];
          } else {
            break;
          }
        }

        valueA = currentObjA;
        valueB = currentObjB;
      }

      if (typeof valueA === "boolean" && typeof valueB === "boolean") {
        return (valueA ? 1 : -1) * this.sortNumber; // Sorting booleans
      } else if (typeof valueA === "number" && typeof valueB === "number") {
        return (valueA - valueB) * this.sortNumber; // Sorting numbers
      } else if (typeof valueA === "string" && typeof valueB === "string") {
        if (valueA.includes(",") && valueB.includes(",")) {
          valueA = valueA.replace(",", "");
          valueB = valueB.replace(",", "");
        }
        if (valueA.includes("/") && valueB.includes("/")) {
          valueA = valueA.replace("/", "");
          valueB = valueB.replace("/", "");
        }

        const dateA = Date.parse(valueA);
        const dateB = Date.parse(valueB);
        const numberA = parseInt(valueA);
        const numberB = parseInt(valueB);

        if (!isNaN(dateA) && !isNaN(dateB)) {
          return (dateA - dateB) * this.sortNumber; // Sorting valid dates as numbers
        } else {
          if (!isNaN(numberA) && !isNaN(numberB)) {
            return (numberA - numberB) * this.sortNumber; // Sorting numbers
          } else {
            return valueA.localeCompare(valueB) * this.sortNumber; // Sorting strings
          }
        }
      }
    });
  }
}
